PRAGMA foreign_keys=ON;
CREATE TABLE IF NOT EXISTS source_artifacts(id TEXT PRIMARY KEY,source_id TEXT NOT NULL,original_filename TEXT NOT NULL,storage_key TEXT NOT NULL,sha256 TEXT NOT NULL,mime_type TEXT,size_bytes INTEGER,retrieved_at TEXT NOT NULL,retrieval_method TEXT NOT NULL,request_reference TEXT,restrictions TEXT,immutable INTEGER NOT NULL DEFAULT 1,FOREIGN KEY(source_id) REFERENCES sources(id));
CREATE TABLE IF NOT EXISTS ingestion_runs(id TEXT PRIMARY KEY,source_id TEXT NOT NULL,source_artifact_id TEXT,status TEXT NOT NULL,parser_version TEXT NOT NULL,schema_version TEXT NOT NULL,started_at TEXT NOT NULL,finished_at TEXT,rows_read INTEGER NOT NULL DEFAULT 0,cases_created INTEGER NOT NULL DEFAULT 0,cases_updated INTEGER NOT NULL DEFAULT 0,cases_unchanged INTEGER NOT NULL DEFAULT 0,records_quarantined INTEGER NOT NULL DEFAULT 0,warnings_json TEXT NOT NULL DEFAULT '[]',rollback_reference TEXT,FOREIGN KEY(source_id) REFERENCES sources(id),FOREIGN KEY(source_artifact_id) REFERENCES source_artifacts(id));
ALTER TABLE judges ADD COLUMN identity_status TEXT NOT NULL DEFAULT 'UNRESOLVED';
CREATE TABLE IF NOT EXISTS judge_aliases(id TEXT PRIMARY KEY,judge_id TEXT NOT NULL,alias TEXT NOT NULL,source_id TEXT,verified_at TEXT,FOREIGN KEY(judge_id) REFERENCES judges(id),FOREIGN KEY(source_id) REFERENCES sources(id));
CREATE TABLE IF NOT EXISTS judge_terms(id TEXT PRIMARY KEY,judge_id TEXT NOT NULL,court TEXT NOT NULL,division TEXT,start_date TEXT,end_date TEXT,term_type TEXT NOT NULL,source_artifact_id TEXT,verification_status TEXT NOT NULL,FOREIGN KEY(judge_id) REFERENCES judges(id),FOREIGN KEY(source_artifact_id) REFERENCES source_artifacts(id));
CREATE TABLE IF NOT EXISTS charges(id TEXT PRIMARY KEY,case_id TEXT NOT NULL,count_number INTEGER,original_code TEXT,original_description TEXT,normalized_statute TEXT,offense_family TEXT,offense_class TEXT,mapping_version TEXT NOT NULL,mapping_status TEXT NOT NULL,FOREIGN KEY(case_id) REFERENCES cases(id));
CREATE TABLE IF NOT EXISTS sentence_components(id TEXT PRIMARY KEY,case_id TEXT NOT NULL,component_type TEXT NOT NULL,numeric_value REAL,unit TEXT,text_value TEXT,concurrent_group TEXT,source_field TEXT,transformation_version TEXT NOT NULL,FOREIGN KEY(case_id) REFERENCES cases(id));
CREATE TABLE IF NOT EXISTS demographic_observations(id TEXT PRIMARY KEY,case_id TEXT NOT NULL,field TEXT NOT NULL,value TEXT,source_system TEXT,collection_method TEXT,quality_status TEXT NOT NULL,public_release_allowed INTEGER NOT NULL DEFAULT 0,FOREIGN KEY(case_id) REFERENCES cases(id));
CREATE TABLE IF NOT EXISTS criminal_history_observations(id TEXT PRIMARY KEY,case_id TEXT NOT NULL,classification TEXT,source_field TEXT,availability_status TEXT NOT NULL,derivation_method TEXT,FOREIGN KEY(case_id) REFERENCES cases(id));
CREATE TABLE IF NOT EXISTS record_provenance(id TEXT PRIMARY KEY,entity_type TEXT NOT NULL,entity_id TEXT NOT NULL,field_name TEXT NOT NULL,source_artifact_id TEXT NOT NULL,source_record_locator TEXT NOT NULL,source_field TEXT,classification TEXT NOT NULL,transformation_version TEXT NOT NULL,first_observed_at TEXT NOT NULL,last_verified_at TEXT NOT NULL,FOREIGN KEY(source_artifact_id) REFERENCES source_artifacts(id));
CREATE TABLE IF NOT EXISTS quarantine_records(id TEXT PRIMARY KEY,ingestion_run_id TEXT NOT NULL,source_artifact_id TEXT NOT NULL,source_record_locator TEXT NOT NULL,reason_code TEXT NOT NULL,details_json TEXT NOT NULL,raw_record_json TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'OPEN',created_at TEXT NOT NULL,resolved_at TEXT,FOREIGN KEY(ingestion_run_id) REFERENCES ingestion_runs(id),FOREIGN KEY(source_artifact_id) REFERENCES source_artifacts(id));
